SELECT /* base.sy :: SyVendorContent :: selectList */ c.* , ste.site_nm AS site_nm , vnd.vendor_nm AS vendor_nm , atg.attach_grp_nm AS attach_grp_nm , cd_vct.code_label AS content_type_cd_nm , cd_vcs.code_label AS vendor_content_status_cd_nm FROM sy_vendor_content c LEFT JOIN sy_site ste ON ste.site_id = c.site_id LEFT JOIN sy_vendor vnd ON vnd.vendor_id = c.vendor_id LEFT JOIN sy_attach_grp atg ON atg.attach_grp_id = c.attach_grp_id LEFT JOIN sy_code cd_vct ON cd_vct.code_grp = 'VENDOR_CONTENT_TYPE' AND cd_vct.code_value = c.content_type_cd LEFT JOIN sy_code cd_vcs ON cd_vcs.code_grp = 'VENDOR_CONTENT_STATUS' AND cd_vcs.code_value = c.vendor_content_status_cd
ORDER BY c.vendor_content_id ASC ORDER BY c.vendor_content_id DESC ORDER BY c.vendor_content_title ASC ORDER BY c.vendor_content_title DESC ORDER BY c.reg_date ASC ORDER BY c.reg_date DESC ORDER BY c.reg_date DESC
LIMIT #{limit} OFFSET #{offset}

SELECT /* base.sy :: SyVendorContent :: selectPageList */ c.* , ste.site_nm AS site_nm , vnd.vendor_nm AS vendor_nm , atg.attach_grp_nm AS attach_grp_nm , cd_vct.code_label AS content_type_cd_nm , cd_vcs.code_label AS vendor_content_status_cd_nm FROM sy_vendor_content c LEFT JOIN sy_site ste ON ste.site_id = c.site_id LEFT JOIN sy_vendor vnd ON vnd.vendor_id = c.vendor_id LEFT JOIN sy_attach_grp atg ON atg.attach_grp_id = c.attach_grp_id LEFT JOIN sy_code cd_vct ON cd_vct.code_grp = 'VENDOR_CONTENT_TYPE' AND cd_vct.code_value = c.content_type_cd LEFT JOIN sy_code cd_vcs ON cd_vcs.code_grp = 'VENDOR_CONTENT_STATUS' AND cd_vcs.code_value = c.vendor_content_status_cd
ORDER BY c.vendor_content_id ASC ORDER BY c.vendor_content_id DESC ORDER BY c.vendor_content_title ASC ORDER BY c.vendor_content_title DESC ORDER BY c.reg_date ASC ORDER BY c.reg_date DESC ORDER BY c.reg_date DESC
LIMIT #{limit} OFFSET #{offset}

