site_id = #{siteId}, vendor_id = #{vendorId}, content_type_cd = #{contentTypeCd}, vendor_content_title = #{vendorContentTitle}, vendor_content_subtitle = #{vendorContentSubtitle}, content_html = #{contentHtml}, thumb_url = #{thumbUrl}, image_url = #{imageUrl}, link_url = #{linkUrl}, attach_grp_id = #{attachGrpId}, lang_cd = #{langCd}, start_date = #{startDate}, end_date = #{endDate}, sort_ord = #{sortOrd}, vendor_content_status_cd = #{vendorContentStatusCd}, use_yn = #{useYn}, view_count = #{viewCount}, vendor_content_remark = #{vendorContentRemark}, upd_by = #{updBy}, upd_date = #{updDate},
